/**
 * Device API 服务
 * Generated by DDF Engine
 */

import request from '@/utils/request'

/**
 * 分页列表
 */
export function getDeviceList(params) {
  return request({
    url: '/api/device',
    method: 'get',
    params,
  })
}

/**
 * 详情
 */
export function getDevice(id) {
  return request({
    url: `/api/device/${id}`,
    method: 'get',
  })
}

/**
 * 创建
 */
export function createDevice(data) {
  return request({
    url: '/api/device',
    method: 'post',
    data,
  })
}

/**
 * 更新
 */
export function updateDevice(id, data) {
  return request({
    url: `/api/device/${id}`,
    method: 'put',
    data,
  })
}

/**
 * 删除
 */
export function deleteDevice(id) {
  return request({
    url: `/api/device/${id}`,
    method: 'delete',
  })
}
